#!/usr/bin/env node

const { execSync, spawn } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

// ============================================================
// CI/CD Pipeline Script for Node.js Applications
// ============================================================

const COLORS = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
};

const CONFIG = {
  nodeVersion: process.env.REQUIRED_NODE_VERSION || '18',
  testTimeout: parseInt(process.env.TEST_TIMEOUT) || 120000,
  buildDir: process.env.BUILD_DIR || 'dist',
  deployTarget: process.env.DEPLOY_TARGET || 'production',
  deployHost: process.env.DEPLOY_HOST || '',
  deployUser: process.env.DEPLOY_USER || 'deploy',
  deployPath: process.env.DEPLOY_PATH || '/var/www/app',
  deployPort: parseInt(process.env.DEPLOY_PORT) || 22,
  healthCheckUrl: process.env.HEALTH_CHECK_URL || '',
  healthCheckRetries: parseInt(process.env.HEALTH_CHECK_RETRIES) || 10,
  healthCheckInterval: parseInt(process.env.HEALTH_CHECK_INTERVAL) || 3000,
  slackWebhook: process.env.SLACK_WEBHOOK_URL || '',
  rollbackOnFailure: process.env.ROLLBACK_ON_FAILURE !== 'false',
  parallelTests: process.env.PARALLEL_TESTS !== 'false',
  cacheDir: process.env.CACHE_DIR || path.join(os.tmpdir(), 'cicd-cache'),
  artifactDir: process.env.ARTIFACT_DIR || 'artifacts',
  maxDeployRetries: parseInt(process.env.MAX_DEPLOY_RETRIES) || 3,
  skipTests: process.env.SKIP_TESTS === 'true',
  skipLint: process.env.SKIP_LINT === 'true',
  dryRun: process.env.DRY_RUN === 'true',
};

// Pipeline state
const pipelineState = {
  startTime: Date.now(),
  stages: [],
  currentStage: null,
  errors: [],
  warnings: [],
  commitHash: '',
  branch: '',
  previousDeployHash: '',
};

// ============================================================
// Utility Functions
// ============================================================

function log(message, color = 'reset') {
  const timestamp = new Date().toISOString();
  console.log(`${COLORS[color]}[${timestamp}] ${message}${COLORS.reset}`);
}

function logStage(stageName) {
  const separator = '='.repeat(60);
  log(`\n${separator}`, 'cyan');
  log(`  STAGE: ${stageName}`, 'cyan');
  log(`${separator}\n`, 'cyan');
}

function logSuccess(message) {
  log(`✅ ${message}`, 'green');
}

function logError(message) {
  log(`❌ ${message}`, 'red');
}

function logWarning(message) {
  log(`⚠️  ${message}`, 'yellow');
  pipelineState.warnings.push(message);
}

function logInfo(message) {
  log(`ℹ️  ${message}`, 'blue');
}

function exec(command, options = {}) {
  const defaults = {
    stdio: 'pipe',
    encoding: 'utf-8',
    timeout: CONFIG.testTimeout,
    env: { ...process.env, FORCE_COLOR: '1' },
  };
  const opts = { ...defaults, ...options };

  logInfo(`Executing: ${command}`);
  const startTime = Date.now();

  try {
    const result = execSync(command, opts);
    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    logInfo(`Completed in ${duration}s`);
    return result ? result.trim() : '';
  } catch (error) {
    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    logError(`Command failed after ${duration}s: ${command}`);
    if (error.stdout) console.log(error.stdout.toString());
    if (error.stderr) console.error(error.stderr.toString());
    throw error;
  }
}

function execSafe(command, options = {}) {
  try {
    return { success: true, output: exec(command, options) };
  } catch (error) {
    return { success: false, error, output: '' };
  }
}

function fileExists(filePath) {
  return fs.existsSync(filePath);
}

function readJson(filePath) {
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf-8'));
  } catch {
    return null;
  }
}

function ensureDir(dirPath) {
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
}

function getElapsedTime() {
  return ((Date.now() - pipelineState.startTime) / 1000).toFixed(2);
}

function generateChecksum(filePath) {
  const crypto = require('crypto');
  const content = fs.readFileSync(filePath);
  return crypto.createHash('md5').update(content).digest('hex');
}

// ============================================================
// Stage Tracking
// ============================================================

function startStage(name) {
  const stage = {
    name,
    startTime: Date.now(),
    status: 'running',
    duration: 0,
  };
  pipelineState.currentStage = stage;
  pipelineState.stages.push(stage);
  logStage(name);
  return stage;
}

function endStage(stage, status = 'success') {
  stage.status = status;
  stage.duration = ((Date.now() - stage.startTime) / 1000).toFixed(2);
  if (status === 'success') {
    logSuccess(`Stage "${stage.name}" completed in ${stage.duration}s`);
  } else if (status === 'skipped') {
    logWarning(`Stage "${stage.name}" skipped`);
  } else {
    logError(`Stage "${stage.name}" failed after ${stage.duration}s`);
  }
}

// ============================================================
// Notification Functions
