async function sendSlackNotification(message, isError = false) {
  if (!CONFIG.slackWebhook) return;

  const payload = {
    attachments: [
      {
        color: isError ? '#ff0000' : '#36a64f',
        title: `CI/CD Pipeline ${isError ? 'Failed' : 'Succeeded'}`,
        text: message,
        fields: [
          { title: 'Branch', value: pipelineState.branch, short: true },
          { title: 'Commit', value: pipelineState.commitHash.substring(0, 8), short: true },
          { title: 'Duration', value: `${getElapsedTime()}s`, short: true },
          { title: 'Target', value: CONFIG.deployTarget, short: true },
        ],
        ts: Math.floor(Date.now() / 1000),
      },
    ],
  };

  try {
    const https = require('https');
    const url = new URL(CONFIG.slackWebhook);

    return new Promise((resolve, reject) => {
      const req = https.request(
        {
          hostname: url.hostname,
          path: url.pathname,
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
        },
        (res) => {
          res.on('data', () => {});
          res.on('end', resolve);
        }
      );
      req.on('error', reject);
      req.write(JSON.stringify(payload));
      req.end();
    });
  } catch (error) {
    logWarning(`Failed to send Slack notification: ${error.message}`);
  }
}

// ============================================================
// Pipeline Stages
