async function stageEnvironmentCheck() {
  const stage = startStage('Environment Check');

  try {
    // Check Node.js version
    const nodeVersion = exec('node --version').replace('v', '');
    const majorVersion = parseInt(nodeVersion.split('.')[0]);
    logInfo(`Node.js version: ${nodeVersion}`);

    if (majorVersion < parseInt(CONFIG.nodeVersion)) {
      throw new Error(
        `Node.js ${CONFIG.nodeVersion}+ required, found ${nodeVersion}`
      );
    }

    // Check npm/yarn/pnpm availability
    const packageManager = detectPackageManager();
    logInfo(`Package manager: ${packageManager}`);

    // Get git info
    const gitResult = execSafe('git rev-parse HEAD');
    if (gitResult.success) {
      pipelineState.commitHash = gitResult.output;
      logInfo(`Commit: ${pipelineState.commitHash}`);
    }

    const branchResult = execSafe('git rev-parse --abbrev-ref HEAD');
    if (branchResult.success) {
      pipelineState.branch = branchResult.output;
      logInfo(`Branch: ${pipelineState.branch}`);
    }

    // Check disk space
    const diskInfo = execSafe('df -h . | tail -1');
    if (diskInfo.success) {
      logInfo(`Disk space: ${diskInfo.output}`);
    }

    // Check available memory
    const totalMem = (os.totalmem() / 1024 / 1024 / 1024).toFixed(2);
    const freeMem = (os.freemem() / 1024 / 1024 / 1024).toFixed(2);
    logInfo(`Memory: ${freeMem}GB free / ${totalMem}GB total`);

    // Verify required files exist
    if (!fileExists('package.json')) {
      throw new Error('package.json not found in current directory');
    }

    const pkg = readJson('package.json');
    logInfo(`Project: ${pkg.name}@${pkg.version}`);

    // Check for required environment variables for deployment
    if (CONFIG.deployTarget === 'production' && !CONFIG.dryRun) {
      if (!CONFIG.deployHost) {
        logWarning('DEPLOY_HOST not set - deployment will be skipped');
      }
    }

    endStage(stage);
    return { packageManager, pkg };
  } catch (error) {
    endStage(stage, 'failed');
    throw error;
  }
}

function detectPackageManager() {
  if (fileExists('pnpm-lock.yaml')) return 'pnpm';
  if (fileExists('yarn.lock')) return 'yarn';
  if (fileExists('package-lock.json')) return 'npm';

  // Default fallback
  const pnpmResult = execSafe('pnpm --version');
  if (pnpmResult.success) return 'pnpm';

  const yarnResult = execSafe('yarn --version');
  if (yarnResult.success) return 'yarn';

  return 'npm';
}

function getInstallCommand(pm) {
  const commands = {
    npm: 'npm ci --prefer-offline --no-audit --no-fund',
    yarn: 'yarn install --frozen-lockfile --non-interactive',
    pnpm: 'pnpm install --frozen-lockfile --prefer-offline',
  };
  return commands[pm] || commands.npm;
}

function getRunCommand(pm, script) {
  const commands = {
    npm: `npm run ${script}`,
    yarn: `yarn ${script}`,
    pnpm: `pnpm run ${script}`,
  };
  return commands[pm] || commands.npm;
}

async function stageInstallDependencies(packageManager) {
  const stage = startStage('Install Dependencies');

  try {
    // Check for dependency cache
    const lockFile = {
      npm: 'package-lock.json',
      yarn: 'yarn.lock',
      pnpm: 'pnpm-lock.yaml',
    }[packageManager];

    let cacheHit = false;
    if (lockFile && fileExists(lockFile)) {
      const checksum = generateChecksum(lockFile);
      const cacheKey = path.join(CONFIG.cacheDir, `node_modules_${checksum}`);

      if (fs.existsSync(cacheKey) && fs.existsSync('node_modules')) {
        logInfo('Dependency cache hit - skipping install');
        cacheHit = true;
      }
    }

    if (!cacheHit) {
      // Clean install
      if (fs.existsSync('node_modules')) {
        logInfo('Cleaning existing node_modules...');
        exec('rm -rf node_modules');
      }

      const installCmd = getInstallCommand(packageManager);
      exec(installCmd, { stdio: 'inherit', timeout: 300000 });

      // Save cache marker
      if (lockFile && fileExists(lockFile)) {
        ensureDir(CONFIG.cacheDir);
        const checksum = generateChecksum(lockFile);
        const cacheKey = path.join(CONFIG.cacheDir, `node_modules_${checksum}`);
        fs.writeFileSync(cacheKey, Date.now().toString());
      }
    }

    // Verify installation
    if (!fs.existsSync('node_modules')) {
      throw new Error('node_modules directory not found after install');
    }

    // Check for security vulnerabilities (non-blocking)
    if (packageManager === 'npm') {
      const auditResult = execSafe('npm audit --production --json');
      if (auditResult.success) {
        try {
          const audit = JSON.parse(auditResult.output);
          if (audit.metadata && audit.metadata.vulnerabilities) {
            const vulns = audit.metadata.vulnerabilities;
            const critical = vulns.critical || 0;
            const high = vulns.high || 0;
            if (critical > 0 || high > 0) {
              logWarning(
                `Security: ${critical} critical, ${high} high vulnerabilities found`
              );
            }
          }
        } catch {
          // Ignore JSON parse errors from audit
        }
      }
    }

    endStage(stage);
  } catch (error) {
    endStage(stage, 'failed');
    throw error;
  }
}

